// Build a fully self-contained Redoc HTML page from docs/openapi.yaml.
//
// The spec is parsed and inlined as JSON, and the page references the *vendored*
// redoc.standalone.js (committed under docs/api/). There are NO external network
// calls (no CDN, no Google Fonts) and NO LLM — the page opens offline by
// double-clicking it. Regenerated by scripts/generate-sdks.sh.
import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parse } from 'yaml';

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const specPath = resolve(repoRoot, 'docs/openapi.yaml');
const outPath = resolve(repoRoot, 'docs/api/index.html');

const spec = parse(readFileSync(specPath, 'utf8'));
// Stable, deterministic serialization so the CI drift check is reproducible.
const specJson = JSON.stringify(spec, null, 0).replace(/</g, '\\u003c');

const html = `<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${spec.info?.title ?? 'API'} — Reference</title>
    <meta name="description" content="Self-contained API reference. No external calls." />
    <style>
      body { margin: 0; padding: 0; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; }
    </style>
  </head>
  <body>
    <div id="redoc"></div>
    <script>
      // The OpenAPI document, inlined so the page is fully offline.
      window.__CLAIMFLOW_SPEC__ = ${specJson};
    </script>
    <!-- Vendored Redoc bundle (committed alongside this file); no CDN. -->
    <script src="./redoc.standalone.js"></script>
    <script>
      Redoc.init(
        window.__CLAIMFLOW_SPEC__,
        { hideDownloadButton: false, expandResponses: '200,201,202', disableSearch: false },
        document.getElementById('redoc'),
      );
    </script>
  </body>
</html>
`;

writeFileSync(outPath, html);
process.stderr.write(`wrote ${outPath} (${html.length} bytes)\n`);
